# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Database connection details
    db_config = {
        'host': 'your_rds_host',
        'user': 'your_username',
        'password': 'your_password',
        'database': 'your_database'
    }
    
    # Extract search parameters from event
    query_params = event.get('queryStringParameters', {})
    where_clause_parts = []
    for key, value in query_params.items():
        where_clause_parts.append(f"{key} LIKE '%{value}%'")
    
    # Build the SQL query dynamically based on search parameters
    if where_clause_parts:
        where_clause = ' AND '.join(where_clause_parts)
        sql_query = f"SELECT * FROM products WHERE {where_clause}"
    else:
        sql_query = "SELECT * FROM products"
    
    try:
        # Establish a connection to the database
        connection = pymysql.connect(**db_config)
        
        # Execute the query
        with connection.cursor() as cursor:
            cursor.execute(sql_query)
            result = cursor.fetchall()
            
            # Convert the result to JSON format
            response = {
                'statusCode': 200,
                'body': json.dumps(result, default=str)
            }
    
    except pymysql.MySQLError as e:
        response = {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    
    finally:
        # Close the database connection
        if connection:
            connection.close()
    
    return response